import{_ as i,c as l,a as n,b as e,e as t,d as p,r as d,o as r}from"./app-CEcM0piI.js";const c={};function u(o,s){const a=d("cache");return r(),l("div",null,[s[4]||(s[4]=n(`<p>ORM(Object Relational Mapping):对象关系映射 两者之间的映射关系</p><table><thead><tr><th>Java概念</th><th>数据库概念</th></tr></thead><tbody><tr><td>类</td><td>表</td></tr><tr><td>属性</td><td>字段/列</td></tr><tr><td>对象</td><td>记录/行</td></tr></tbody></table><p>指的是持久化数据和实体对象的映射模式，为了解决面向对象与关系型数据库存在的互不匹配的现象的技术。</p><p><strong>原始JDBC的操作问题分析:</strong></p><ol><li>频繁创建和销毁数据库的连接会造成系统资源浪费从而影响系统性能。</li><li>sql语句在代码中硬编码，如果要修改sql语句，就需要修改java代码，造成代码不易维护。</li><li>查询操作时，需要手动将结果集中的数据封装到实体对象中。</li><li>增删改查操作需要参数时，需要手动将实体对象的数据设置到sql语句的占位符。</li></ol><p><strong>MyBatis</strong></p><ul><li>MyBatis是一个优秀的基于Java的持久层框架，它内部封装了JDBC，使开发者只需要关注SQL语句本身，而不需要花费精力去处理加载驱动、创建连接、创建执行者等复杂的操作。</li><li>MyBatis通过xml或注解的方式将要执行的各种Statement配置起来，并通过Java对象和Statement中SQL的动态参数进行映射生成最终要执行的SQL语句。</li><li>最后MyBatis框架执行完SQL并将结果映射为Java对象并返回。采用ORM思想解决了实体和数据库映射的问题，对JDBC进行了封装，屏蔽了JDBCAPI底层访问细节，使我们不用与JDBCAPI打交道，就可以完成对数据库的持久化操作。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>        //加载mybatis的核心配置文件，获取SqLSessionFactory</span></span>
<span class="line"><span>        String resource=&quot;mybatis-config.xml&quot;;</span></span>
<span class="line"><span>        InputStream inputStream=Resources.getResourceAsStream(resource);</span></span>
<span class="line"><span>        SqlSessionFactory sqlSessionFactory=new SqlSessionFactoryBuilder().build(inputStream);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>        //获取SqlSession对象用于执行sql</span></span>
<span class="line"><span>        SqlSession sqlSession=sqlSessionFactory.openSession();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        //执行sql</span></span>
<span class="line"><span>        List&lt;User&gt; users=sqlSession.selectList(&quot;test.selectAll&quot;);</span></span>
<span class="line"><span>        System.out.println(users);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        //释放资源</span></span>
<span class="line"><span>        sqlSession.close();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>代理开发</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>        //加载mybatis的核心配置文件，获取SqLSessionFactory</span></span>
<span class="line"><span>        String resource=&quot;mybatis-config.xml&quot;;</span></span>
<span class="line"><span>        InputStream inputStream=Resources.getResourceAsStream(resource);</span></span>
<span class="line"><span>        SqlSessionFactory sqlSessionFactory=new SqlSessionFactoryBuilder().build(inputStream);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>        //获取SqlSession对象用于执行sql</span></span>
<span class="line"><span>        SqlSession sqlSession=sqlSessionFactory.openSession();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        //获取UserMapper代理对象</span></span>
<span class="line"><span>        UserMapper userMapper=sqlSession.getMapper(UserMapper.class);</span></span>
<span class="line"><span>        List&lt;User&gt; users=userMapper.selectAll();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        //执行sql</span></span>
<span class="line"><span>        // List&lt;User&gt; users=sqlSession.selectList(&quot;test.selectAll&quot;);</span></span>
<span class="line"><span>        System.out.println(users);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        //释放资源</span></span>
<span class="line"><span>        sqlSession.close();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>openSession默认不自动提交事务,因此在进行删改操作时需要手动提交<code>sqlSession.commit()</code> 也可以在获取SqlSession对象时开始自动提交<code>sqlSessionFactory.openSession(true); </code></p><h2 id="核心配置文件" tabindex="-1"><a class="header-anchor" href="#核心配置文件"><span>核心配置文件</span></a></h2><p>习惯上命名为mybatis-config.xml，这个文件名仅仅只是建议，并非强制要求。将来整合Spring之后，这个配置文件可以省略 resource文件夹下</p><div class="language-mybatis-config.xml line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="mybatis-config.xml" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;</span></span>
<span class="line"><span>&lt;!DOCTYPE configuration PUBLIC &quot;-//mybatis.org//DTD Config 3.0//EN&quot; &quot;http://mybatis.org/dtd/mybatis-3-config.dtd&quot;&gt;</span></span>
<span class="line"><span>&lt;configuration&gt;</span></span>
<span class="line"><span>    &lt;!-- 配置连接数据库的环境 --&gt;</span></span>
<span class="line"><span>    &lt;environments default=&quot;development&quot;&gt;</span></span>
<span class="line"><span>        &lt;environment id=&quot;development&quot;&gt;</span></span>
<span class="line"><span>            &lt;transactionManager type=&quot;JDBC&quot; /&gt;</span></span>
<span class="line"><span>            &lt;dataSource type=&quot;POOLED&quot;&gt;</span></span>
<span class="line"><span>                &lt;property name=&quot;driver&quot; value=&quot;com.mysql.jdbc.Driver&quot; /&gt;</span></span>
<span class="line"><span>                &lt;property name=&quot;url&quot; value=&quot;jdbc:mysql:///mybatis?useSSL=false&quot; /&gt;</span></span>
<span class="line"><span>                &lt;property name=&quot;username&quot; value=&quot;root&quot; /&gt;</span></span>
<span class="line"><span>                &lt;property name=&quot;password&quot; value=&quot;030604&quot; /&gt;</span></span>
<span class="line"><span>            &lt;/dataSource&gt;</span></span>
<span class="line"><span>        &lt;/environment&gt;</span></span>
<span class="line"><span>    &lt;/environments&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    &lt;!-- 引入映射文件 --&gt;</span></span>
<span class="line"><span>    &lt;mappers&gt;</span></span>
<span class="line"><span>        &lt;mapper resource=&quot;com/example/mapper/UserMapper.xml&quot; /&gt;</span></span>
<span class="line"><span>    &lt;/mappers&gt;</span></span>
<span class="line"><span>&lt;/configuration&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>复数标签内部都可以包含多个同名的单数标签</p><ul><li>environments : 配置多个数据库环境 default : 默认使用的环境id</li><li>environment : 配置具体的环境 id : 表示连接数据库环境的唯一标识,不能重复</li><li>transactionManager : 事务管理方式 type : JDBC标识当前环境中执行事务时使用jdbc原生的事务管理方式(事务的提交或回滚需要手动处理) MANAGED被管理,如spring等</li><li>dataSource : 数据源 type : 数据源类型 POOLED：表示使用数据库连接池缓存数据库连接 UNPOOLED：表示不使用数据库连接池 JNDI：表示使用上下文中的数据源</li></ul><p>数据库连接配置也可以写在外部的.prooperties文件夹中,然后使用properties标签导入</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;environment&gt;</span></span>
<span class="line"><span>	&lt;properties resource=&quot;jdbc.properties&quot; /&gt;</span></span>
<span class="line"><span>	&lt;dataSource type=&quot;POOLED&quot;&gt;</span></span>
<span class="line"><span>		&lt;！--设置连接数据库的驱动--&gt;</span></span>
<span class="line"><span>		&lt;property name=&quot;driver&quot; value=&quot;\${jdbc.driver}&quot;/&gt;</span></span>
<span class="line"><span>		&lt;！--设置连接数据库的连接地址--&gt;</span></span>
<span class="line"><span>		&lt;property name=&quot;url&quot; value=&quot;\${jdbc.url}&quot;/&gt;</span></span>
<span class="line"><span>		&lt;！--设置连接数据库的用户名--&gt;</span></span>
<span class="line"><span>		&lt;property name=&quot;username&quot;value=&quot;\${jdbc.username}&quot;/&gt;</span></span>
<span class="line"><span>		&lt;！--设置连接数据库的密码--&gt;</span></span>
<span class="line"><span>		&lt;property name=&quot;password&quot;value=&quot;\${jdbc.password}&quot;/&gt;</span></span>
<span class="line"><span>	&lt;/dataSource&gt;</span></span>
<span class="line"><span>&lt;/environment&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>设置类型别名</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;typeAliases&gt;</span></span>
<span class="line"><span>	&lt;typeAlias type=&quot;com.atguigu.mybatis.pojo.User&quot; alias=&quot;User&quot;&gt;&lt;/typeAlias&gt;</span></span>
<span class="line"><span>&lt;/typeAliases&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>将全类名设置User别名,这样在设置resultType属性时就不用写那么长,直接使用类型别名即可 如果不设置别名就默认设置为类名,不区分大小写</p><p>一般不使用默认的别名 可以以包为单位批量设置类型的默认别名</p><p>以包为单位，将包下所有的类型设置默认的类型别名，即类名且不区分大小写</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;package name=&quot;com.atguigu.mybatis.pojo&quot;/&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="创建mapper接口" tabindex="-1"><a class="header-anchor" href="#创建mapper接口"><span>创建mapper接口</span></a></h2><p><mark>MyBatis面向接口编程的两个一致：</mark></p><ol><li>映射文件的namespace要和mapper接口的全类名保持一致</li><li>映射文件中sql语句的id要和mapper接口中的方法名一致</li></ol><p>MyBatis中的mapper接口相当于以前的dao。但是区别在于，mapper仅仅是接口，我们不需要提供实现类。</p><div class="language-mybatis\\src\\main\\java\\com\\example\\mapper\\usermapper.java line-numbers-mode" data-highlighter="shiki" data-ext="mybatis\\src\\main\\java\\com\\example\\mapper\\usermapper.java" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public interface UserMapper {</span></span>
<span class="line"><span>    List&lt;User&gt; selectAll();</span></span>
<span class="line"><span>    User selectById(int id);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>映射文件要和接口放在同一文件夹下 java在编译后会将resources文件夹与java文件夹合并,也就是说在resources文件夹下创建一个同名路径文件夹存放映射文件</p><div class="language-mybatis\\src\\main\\resources\\com\\example\\mapper\\usermapper.xml line-numbers-mode" data-highlighter="shiki" data-ext="mybatis\\src\\main\\resources\\com\\example\\mapper\\usermapper.xml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;</span></span>
<span class="line"><span>&lt;!DOCTYPE mapper PUBLIC &quot;-//mybatis.org//DTD Mapper 3.0//EN&quot; &quot;http://mybatis.org/dtd/mybatis-3-mapper.dtd&quot;&gt;</span></span>
<span class="line"><span>&lt;mapper namespace=&quot;com.example.mapper.UserMapper&quot;&gt;</span></span>
<span class="line"><span>    &lt;select id=&quot;selectAll&quot; resultType=&quot;user&quot;&gt;</span></span>
<span class="line"><span>        select * from tb_user;</span></span>
<span class="line"><span>    &lt;/select&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    &lt;!-- selectById --&gt; </span></span>
<span class="line"><span></span></span>
<span class="line"><span>    &lt;select id=&quot;selectById&quot; resultType=&quot;user&quot;&gt;</span></span>
<span class="line"><span>        select * from tb_user where id = #{id};</span></span>
<span class="line"><span>    &lt;/select&gt;</span></span>
<span class="line"><span>&lt;/mapper&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>映射接口中不需要实现类,调用该接口执行sql语句,需要在映射文件中定义sql语句 接口函数有返回类型的映射文件中对应id的标签中也要指定同样类型的resultType,如果是自定义类可能需要全类名 resultType : 设置默认的映射关系,当实体类型设置出来之后会自动地把当前查询结果的字段名作为属性名为当前类的属性进行赋值,如果能匹配到就赋值,匹配不到就不赋值 resultMap : 设置自定义的映射关系,当字段名和属性名不一致的时候就用到resultMap</p><h1 id="" tabindex="-1"><a class="header-anchor" href="#"><span></span></a></h1><p>\${ } : 本质是字符串拼接,没有防止sql注入的功能 #{ } : 本质是占位符赋值,有防止sql注入的功能</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public interface UserMapper{</span></span>
<span class="line"><span>	User getuserByUsername(String username);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//映射文件中</span></span>
<span class="line"><span>&lt;select id=&quot;getuserByUsername&quot; resultType=&quot;User&quot;&gt;</span></span>
<span class="line"><span>	select * from t_user where username = #{username};</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>#{}</code>的大括号中的字符可以是任意字符,无需和方法的形参一致</p><p>但\${}需要使用单引号引用起来将其转换成字符串</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//映射文件中</span></span>
<span class="line"><span>&lt;select id=&quot;getuserByUsername&quot; resultType=&quot;User&quot;&gt;</span></span>
<span class="line"><span>	select * from t_user where username = &#39;\${username}&#39;;</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但两种方法在使用多参数时就不能随意写字符了,必须按照参数列表的顺序分配占位符为arg0,arg1或者param1,param2的形式,这两种形式可以混合使用,arg是从0开始的,param是从1开始的,arg1和param2指代的是同一个参数</p><p>mybatis会将参数放到map集合中,以arg0,arg1...为键(或param1,param2...)以参数值为值</p><p>可以自己将参数和自定义的键放到一个map集合中,再传参的时候传入这个map集合,这样在映射文件中多参数的情况下就可以使用自定义字符了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public interface ParameterMapper{</span></span>
<span class="line"><span>	//验证登录（参数为map）</span></span>
<span class="line"><span>	User checkLoginByMap(Map&lt;String, Object&gt; map);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Map&lt;String,object&gt;mapnew HashMap&lt;&gt;();</span></span>
<span class="line"><span>map.put(&quot;username&quot;,&quot;admin&quot;);</span></span>
<span class="line"><span>map.put(&quot;password&quot;,&quot;123456&quot;);</span></span>
<span class="line"><span>User user=mapper.checkLoginByMap(map);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;select id=&quot;checkLoginByMap&quot; resultType=&quot;User&quot;&gt;</span></span>
<span class="line"><span>	select * from t_user where username = #{username} and password= #{password}</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当插入数据时传入的是一个实体类对象,可以直接使用实体类对象中的成员变量名获取值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mapper.insert(User);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;select id=&quot;insert&quot;&gt;</span></span>
<span class="line"><span>	insert into tb_user valuses(#{id},#{name},#{age},#{email})</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用@param注解</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>User checkLoginByParam(@Param(&quot;username&quot;) String username , @Param(&quot;password&quot;) String password)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User user = mapper.checkLoginByParam(&quot;admin&quot;, &quot;123456&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;select id=&quot;checkLoginByParam&quot; resultType=&quot;User&quot;&gt;</span></span>
<span class="line"><span>	select * from t_user where username = #{username} and password = #{password}</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样的话mybatis底层在map存储的时候就会以@param中的参数为键传入参数为值构建map集合,取代了arg但是param没有被取代</p><p>当查询时如果接口中的返回值是单个的话而查询结果是多个就会报错 可以使用集合或数组作为返回值,这样既可以返回多个也可以返回单个</p><p>int类型在resultType中需要指定为Integer类型</p><p>可以将resultType指定为map类型,这样获取到的结果就会以字段为键,以数据为值</p><p>当有多条数据的的时候可以将其转换为一个map数组也可以指定map的键让整条数据作为值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@MapKey(&quot;id&quot;)</span></span>
<span class="line"><span>Map&lt;string,object&gt;getAllUserToMap();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>返回结果</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>	3={pasgword=123456,sex=男,id=3,age=23,email=12345@qq.com,username=admin},</span></span>
<span class="line"><span>	6={password=123，sex=男，id=6,age=23，email=123@qq.com，username=李四}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="不能使用-的场景" tabindex="-1"><a class="header-anchor" href="#不能使用-的场景"><span>不能使用#{}的场景</span></a></h3><h4 id="模糊匹配" tabindex="-1"><a class="header-anchor" href="#模糊匹配"><span>模糊匹配</span></a></h4><p>当进行模糊匹配的时候由于模糊匹配的内容都是字符串类型的所以需要使用单引号引起来,如果使用#{}的话就会导致内容被解读为字符串,所以模糊匹配是要用到\${}</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;select id=&quot;getUserByLike&quot;resultType=&quot;User&quot;&gt;</span></span>
<span class="line"><span>	select * from t user where username like &#39;%\${username}%&#39;</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果使用#{}的话需要多次拼接</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select * from t user where username like&quot;%&quot;#{username}&quot;%&quot;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="批量删除" tabindex="-1"><a class="header-anchor" href="#批量删除"><span>批量删除</span></a></h4><p>当传入多个id进行批量删除时不能使用#{},因为在使用#{}时会自动加单引号所以无法实现批量删除</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mapper.deleteMore(&quot;1,2,3&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>delete from t user where id in (\${ids})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="动态设置表名" tabindex="-1"><a class="header-anchor" href="#动态设置表名"><span>动态设置表名</span></a></h4><p>这是因为在查询表明的时候是没有单引号的,而#{}会自动添加单引号</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select from \${tableName}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="获取自动递增的主键" tabindex="-1"><a class="header-anchor" href="#获取自动递增的主键"><span>获取自动递增的主键</span></a></h3><p>useGeneratedKeys : 表明要执行的sql是否使用自动递增主键 获取到的自动递增的主键值放在哪里(传参的变量中),将其当作传出参数,这是因为返回值是固定的所以只能将该值放到传出参数中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void insertuser(User user);</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;insert id=&quot;insertuser&quot; useGeneratedKeys=&quot;true&quot; keyProperty=&quot;id&quot;&gt;</span></span>
<span class="line"><span>	insert into t_user values(null,#{username},#{password},#{age},#{sex},#{email})</span></span>
<span class="line"><span>&lt;/insert&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Preparedstatement ps =connection.preparestatement(sql:&quot;insert&quot;,RETURN_GENERATED_KEYS)</span></span>
<span class="line"><span>User user=new User(new User(id:null,username:&quot;王五&quot;，password:&quot;123&quot;，age:23，sex:&quot;男&quot;，email:&quot;123@163.com&quot;));</span></span>
<span class="line"><span>mapper.insertuser(user);</span></span>
<span class="line"><span>System.out.println(user)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>preparestatement(sql:&quot;insert&quot;,RETURN_GENERATED_KEYS)设置是否能获取自动递增的主键</p><h2 id="字段名和属性名不一致的情况" tabindex="-1"><a class="header-anchor" href="#字段名和属性名不一致的情况"><span>字段名和属性名不一致的情况</span></a></h2><h3 id="为字段起别名使其符合属性名" tabindex="-1"><a class="header-anchor" href="#为字段起别名使其符合属性名"><span>为字段起别名使其符合属性名</span></a></h3><p>如果字段名和属性名不一致时那么查询出来的结果就为空,可以在查询时给字段设置别名来解决</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class User{</span></span>
<span class="line"><span>	string empName;</span></span>
<span class="line"><span>	int empAge;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>select emp_name empName,emp_age emp_Age from emp;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="设置setting属性" tabindex="-1"><a class="header-anchor" href="#设置setting属性"><span>设置setting属性</span></a></h3><p>在核心配置文件添加mapUnderscoreTocamelcase配置设置为true表明自动将下划线命名映射为驼峰命名(单驼峰)</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;settings&gt;</span></span>
<span class="line"><span>	&lt;!--将_自动映射为驼峰，em_pnqme:empName--&gt;</span></span>
<span class="line"><span>	&lt;setting name=&quot;mapUnderscoreTocamelcase&quot; value=&quot;true&quot;/&gt;</span></span>
<span class="line"><span>&lt;/settings&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但映射也是有规则的,如:emp_name只能映射为empName</p><h3 id="通过reslutmap" tabindex="-1"><a class="header-anchor" href="#通过reslutmap"><span>通过reslutMap</span></a></h3><p>&lt;resultMap&gt;标签设置resultMap要处理的映射关系</p><ul><li>id : 表示自己的id</li><li>type : 表示要处理映射关系的类名 其中&lt;id&gt;标签处理的是主键的映射关系 &lt;result&gt;标签处理的是普通字段的映射关系 &lt;association&gt;标签处理多对一的映射关系 &lt;collection&gt;标签处理一对多的映射关系</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;resultMap id=&quot;empResultMap&quot; type=&quot;Emp&quot;&gt;</span></span>
<span class="line"><span>	&lt;id property=&quot;eid&quot;column=&quot;eid&quot;&gt;&lt;/id&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;empName&quot; column=&quot;emp_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;empAge&quot; column=&quot;emp_age&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>&lt;/resultMap&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;select id=&quot;getAllEmpre&quot; sultMap=&quot;empResultMap&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果有的字段名和属性名一致可以不设置,但为了严谨性推荐设置</p><h3 id="多表查询与类中自定义类型的映射" tabindex="-1"><a class="header-anchor" href="#多表查询与类中自定义类型的映射"><span>多表查询与类中自定义类型的映射</span></a></h3><p>如果在一个实体类中有一个自定义类型对应着另一张表,而查询时需要多表查询,查询出的结果只是基础数据类型无法对应自定义类型,此时就需要进行级联映射</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;resultMap id=&quot;empResultMapOne&quot; type=&quot;Emp&quot;&gt;</span></span>
<span class="line"><span>	&lt;id property=&quot;eid&quot;column=&quot;eid&quot;&gt;&lt;/id&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;empName&quot; column=&quot;emp_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;empAge&quot; column=&quot;emp_age&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;dept.did&quot; column=&quot;did&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;dept.deptName&quot; column=&quot;dept_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>&lt;/resultMap&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;selectid=&quot;getEmpAndDept&quot; resultMap=&quot;empAndDeptResultMapOne&quot;&gt;</span></span>
<span class="line"><span>	select * from t_emp left join t_dept on t_emp.did = t_dept.did where t_emp.eid = #{eid}</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="association处理多对一的关系" tabindex="-1"><a class="header-anchor" href="#association处理多对一的关系"><span>association处理多对一的关系</span></a></h3><p>property指明的多映射的表 javaType指明的java实体类,其中的id标签和result标签和result标签一样 和resultMap嵌套使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;resultMap&gt;</span></span>
<span class="line"><span>	&lt;id property=&quot;eid&quot;column=&quot;eid&quot;&gt;&lt;/id&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;empName&quot; column=&quot;emp_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;empAge&quot; column=&quot;emp_age&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;dept.did&quot; column=&quot;did&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;dept.deptName&quot; column=&quot;dept_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;association property=&quot;dept&quot; javaType=&quot;Dept&quot;&gt;</span></span>
<span class="line"><span>		&lt;id property=&quot;did&quot; column=&quot;did&quot;&gt;&lt;/id&gt;</span></span>
<span class="line"><span>		&lt;result property=&quot;deptName&quot; column=&quot;dept_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;/association&gt;</span></span>
<span class="line"><span>&lt;/resultMap&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="分步查询" tabindex="-1"><a class="header-anchor" href="#分步查询"><span>分步查询</span></a></h3><p>分步查询最大的优点是可以开始延迟加载 需要在setting标签中开启 开启延迟加载后所有分步查询都会延迟加载了,如果有的分步查询不需要延迟加载可以在属性中设置 association中的fetchType属性设置为lazy是延迟加载,eager是关闭延迟加载</p><h3 id="一对多" tabindex="-1"><a class="header-anchor" href="#一对多"><span>一对多</span></a></h3><p>如查询一个部门表中会返回多个员工</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;resultMap id=&quot;deptAndEmpResultMap&quot;ttype=&quot;Dept&quot;&gt;</span></span>
<span class="line"><span>	&lt;id property=&quot;did&quot;&#39;column=&quot;did&quot;&gt;&lt;/id&gt;</span></span>
<span class="line"><span>	&lt;result property=&quot;deptName&quot;column=&quot;dept_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;collection property=&quot;emps&quot; ofType=&quot;Emp&quot;&gt;</span></span>
<span class="line"><span>		&lt;id property=&quot;eid&quot;column=&quot;eid&quot;&gt;&lt;/id&gt;</span></span>
<span class="line"><span>		&lt;result property=&quot;empName&quot; column=&quot;emp_name&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>		&lt;result property=&quot;age&quot; column=&quot;age&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>		&lt;result property=&quot;sex&quot; column=&quot;sex&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>		&lt;result property=&quot;email&quot; column=&quot;eid&quot;&gt;&lt;/result&gt;</span></span>
<span class="line"><span>	&lt;/collection&gt;</span></span>
<span class="line"><span>&lt;/resultMap&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;select id=&quot;getDeptAndEmp&quot; resultMap=&quot;deptAndEmpResultMap&quot;&gt;</span></span>
<span class="line"><span>	select * from t_dept left join t_emp on t_dept.did = t_emp.did where t_dept.did = #{did}</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="动态sql" tabindex="-1"><a class="header-anchor" href="#动态sql"><span>动态sql</span></a></h1><p>可以更方便地拼接sql语句</p><h2 id="if" tabindex="-1"><a class="header-anchor" href="#if"><span>if</span></a></h2><p>if标签可通过test属性的表达式进行判断，若表达式的结果为true，则标签中的内容会执行；反之标签中的内容不会执行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;select id=&quot;getEmpByCondition&quot; resultType=&quot;Emp&quot;&gt;</span></span>
<span class="line"><span>	select * from t_emp where</span></span>
<span class="line"><span>	&lt;if test=&quot;ename != null and ename !=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>		ename=#{ename}</span></span>
<span class="line"><span>	&lt;/if&gt;</span></span>
<span class="line"><span>	&lt;if test= &quot;age != null and age !=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>		and age=#{age}</span></span>
<span class="line"><span>	&lt;/if&gt;</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>由于&amp;&amp;和||有特殊含义故用and和or代替</p><p>但如果第一个if没有执行成功而后面的if执行成功了就会出现where and不符合语法 或者所有if都没有执行成功就会出现语句后多了一个where sql出现错误 此时可以在where后面加上一个永真式来解决,这样第一个if中也要加入and</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;select id=&quot;getEmpByCondition&quot; resultType=&quot;Emp&quot;&gt;</span></span>
<span class="line"><span>	select * from t_emp where 1=1</span></span>
<span class="line"><span>	&lt;if test=&quot;ename != null and ename !=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>		and ename=#{ename}</span></span>
<span class="line"><span>	&lt;/if&gt;</span></span>
<span class="line"><span>	&lt;if test= &quot;age != null and age !=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>		and age=#{age}</span></span>
<span class="line"><span>	&lt;/if&gt;</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="where" tabindex="-1"><a class="header-anchor" href="#where"><span>where</span></a></h2><p>对于多余where的问题也可以使用where标签去动态生成where</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;select id=&quot;getEmpByCondition&quot; resultType=&quot;Emp&quot;&gt;</span></span>
<span class="line"><span>	select * from t_emp</span></span>
<span class="line"><span>	&lt;where&gt;</span></span>
<span class="line"><span>		&lt;if test=&quot;ename != null and ename !=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>			ename=#{ename}</span></span>
<span class="line"><span>		&lt;/if&gt;</span></span>
<span class="line"><span>		&lt;if test= &quot;age != null and age !=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>			and age=#{age}</span></span>
<span class="line"><span>		&lt;/if&gt;</span></span>
<span class="line"><span>	&lt;/where&gt;</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当where标签中判断语句都不为真的时候就不慌生成where,如果为真也会自动去除<strong>内容前</strong>的and或or 不能将内容后多余的and或or去掉</p><h2 id="trim" tabindex="-1"><a class="header-anchor" href="#trim"><span>trim</span></a></h2><p>若标签中有内容时: prefix / suffix：将trim标签中内容前面或后面添加指定内容 suffixoverrides / prefixoverrides：将trim标签中内容前面或后面去掉指定内容</p><p>若标签内没有内容: trim标签也没有任何效果</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;trim prefix=&quot;where&quot; suffixoverrides=&quot;and|or&quot;&gt;</span></span>
<span class="line"><span>	&lt;if test=&quot;empNamee != null and empName!=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>		emp_name = #{empName}and</span></span>
<span class="line"><span>	&lt;/if&gt;</span></span>
<span class="line"><span>	&lt;if test=&quot;age != null and age!=&#39;&#39;&quot;&gt;</span></span>
<span class="line"><span>		age = #{age} or</span></span>
<span class="line"><span>	&lt;/if&gt;</span></span>
<span class="line"><span>&lt;/trim&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="choose-when-otherwise" tabindex="-1"><a class="header-anchor" href="#choose-when-otherwise"><span>choose,when,otherwise</span></a></h2><p>when和otherwise标签都需要写在choose标签里面 when相当于if,else if toherwise相当于else</p><h2 id="foreach" tabindex="-1"><a class="header-anchor" href="#foreach"><span>foreach</span></a></h2><p>遍历一个数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;!--int deleteMoreByArray(@Param(eids) Integer[]eids);--&gt;</span></span>
<span class="line"><span>&lt;delete id=&quot;deleteMoreByArray&quot;&gt;</span></span>
<span class="line"><span>	delete from t_emp where eid in(</span></span>
<span class="line"><span>	&lt;foreach collection=&quot;eids&quot; item=&quot;eid&quot; separator:&quot;,&quot;&gt;</span></span>
<span class="line"><span>		#{eid}</span></span>
<span class="line"><span>	&lt;/foreach&gt;)</span></span>
<span class="line"><span>&lt;/delete&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>根据id数组批量删除符合id的数据 collection是传入的数组名,元素是每次循环拿出的元素<code>相当于for(item:collection)</code> separator表示的是分隔符,每个元素之间用什么分隔(如果自己在#{}后写分割符在开头或结尾元素会多出一个)生成的分隔符左右默认加上空格 open属性表示以什么开始 close属性标表示以什么结束</p><p>这样就可以省略自己写小括号了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;!--int deleteMoreByArray(@Param(eids) Integer[]eids);--&gt;</span></span>
<span class="line"><span>&lt;delete id=&quot;deleteMoreByArray&quot;&gt;</span></span>
<span class="line"><span>	delete from t_emp where eid in</span></span>
<span class="line"><span>	&lt;foreach collection=&quot;eids&quot; item=&quot;eid&quot; separator:&quot;,&quot; open&quot;()&quot; close=&quot;)&quot;&gt;</span></span>
<span class="line"><span>		#{eid}</span></span>
<span class="line"><span>	&lt;/foreach&gt;</span></span>
<span class="line"><span>&lt;/delete&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>也可以用于or或and 的单一场景</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>delete from t_emp where</span></span>
<span class="line"><span>&lt;foreach collection=&quot;eids&quot; item=&quot;eid&quot; separator=&quot;or&quot;&gt;</span></span>
<span class="line"><span>	eid = #{eid}</span></span>
<span class="line"><span>&lt;/foreach&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="sql和include" tabindex="-1"><a class="header-anchor" href="#sql和include"><span>sql和include</span></a></h2><p>sql标签用于定义变量 include用于引入变量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;sql id=&quot;empcolumns&quot;&gt;eid,emp_name,age,sex,email&lt;/sql&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;!--List&lt;Emp&gt; getEmpByCondition(Emp emp);--&gt;</span></span>
<span class="line"><span>&lt;select id=&quot;getEmpByCondition&quot; resultType=&quot;Emp&quot;&gt;</span></span>
<span class="line"><span>	select &lt;include refid=empcolumns&gt;&lt;/include&gt; from t_emp</span></span>
<span class="line"><span>&lt;/select&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="缓存" tabindex="-1"><a class="header-anchor" href="#缓存"><span>缓存</span></a></h1><h2 id="一级缓存" tabindex="-1"><a class="header-anchor" href="#一级缓存"><span>一级缓存</span></a></h2><p>一级缓存是默认开启的 一级缓存是SqISession级别的，通过同一个SqISession查询的数据会被缓存，下次查询相同的数据，就会从缓存中直接获取，不会从数据库重新访问</p><p>使一级缓存失效的四种情况：</p><ol><li>不同的SqISession对应不同的一级缓存</li><li>同一个SqISession但是查询条件不同</li><li>同一个SqISession两次查询期间执行了任何一次增删改操作(只要执行增删改都会情况缓存)</li><li>同一个SqISession两次查询期间手动清空了缓存</li></ol><h2 id="二级缓存" tabindex="-1"><a class="header-anchor" href="#二级缓存"><span>二级缓存</span></a></h2><p>二级缓存是SqlSessionFactory级别，通过同一个SqlSessionFactory创建的SqlSession查询的结果会被缓存；此后若再次执行相同的查询语句，结果就会从缓存中获取</p><p>二级缓存开启的条件：</p>`,131)),e("ol",null,[s[1]||(s[1]=e("li",null,'在核心配置文件中，设置全局配置属性cacheEnabled="true"，默认为true，不需要设置',-1)),e("li",null,[s[0]||(s[0]=t("在映射文件中设置标签")),p(a)]),s[2]||(s[2]=e("li",null,"二级缓存必须在SqISession关闭或提交之后有效",-1)),s[3]||(s[3]=e("li",null,"查询的数据所转换的实体类类型必须实现序列化的接口",-1))]),s[5]||(s[5]=n(`<p>使二级缓存失效的情况： 两次查询之间执行了任意的增删改，会使一级和二级缓存同时失效</p><h3 id="相关属性" tabindex="-1"><a class="header-anchor" href="#相关属性"><span>相关属性</span></a></h3><p>在mapper配置文件中添加的cache标签可以设置一些属性：</p><p><strong>eviction属性：缓存回收策略</strong> 默认的是LRU。</p><ul><li>LRU（LeastRecentlyUsed）－最近最少使用的：移除最长时间不被使用的对象。</li><li>FIFO（First in First out）-先进先出：按对象进入缓存的顺序来移除它们。</li><li>SOFT-软引用：移除基于垃圾回收器状态和软引用规则的对象。</li><li>WEAK-弱引用：更积极地移除基于垃圾收集器状态和弱引用规则的对象。</li></ul><p><strong>flushlnterval属性：刷新间隔，单位毫秒</strong> 二级缓存每隔多长时间刷新一次 默认情况是不设置，也就是没有刷新间隔，缓存仅仅调用语句时刷新</p><p><strong>size属性：引用数目，正整数</strong> 代表缓存最多可以存储多少个对象，太大容易导致内存溢出</p><p><strong>readOnly属性：只读，true/false</strong></p><ul><li>true：只读缓存；会给所有调用者返回缓存对象的相同实例。因此这些对象不能被修改。这提供了很重要的性 能优势。</li><li>false：读写缓存；会返回缓存对象的拷贝（通过序列化）。这会慢一些，但是安全，因此默认是false。</li></ul><h2 id="缓存的查询顺序" tabindex="-1"><a class="header-anchor" href="#缓存的查询顺序"><span>缓存的查询顺序</span></a></h2><ul><li>先查询二级缓存，因为二级缓存中可能会有其他程序已经查出来的数据，可以拿来直接使用。</li><li>如果二级缓存没有命中，再查询一级缓存</li><li>如果一级缓存也没有命中，则查询数据库</li><li>SqlSession关闭之后，一级缓存中的数据会写入二级缓存</li></ul><h2 id="第三方缓存" tabindex="-1"><a class="header-anchor" href="#第三方缓存"><span>第三方缓存</span></a></h2><p>mybatis由于是主要用于操作数据库,故缓存方面可能有做的不好的地方,mybatis也提供了二级缓存的接口可以使用第三方缓存管理二级缓存 但一级缓存是无法更改的</p><h3 id="ehcache" tabindex="-1"><a class="header-anchor" href="#ehcache"><span>EHCache</span></a></h3><div class="language-pom.xml line-numbers-mode" data-highlighter="shiki" data-ext="pom.xml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;!--MybatisEHCache整合包--&gt;</span></span>
<span class="line"><span>&lt;dependency&gt;</span></span>
<span class="line"><span>	&lt;groupId&gt;org.mybatis.caches&lt;/groupId&gt;</span></span>
<span class="line"><span>	&lt;artifactId&gt;mybatis-ehcache&lt;/artifactId&gt;</span></span>
<span class="line"><span>	&lt;version&gt;1.2.1&lt;/version&gt;</span></span>
<span class="line"><span>&lt;/dependency&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>核心配置文件</p><div class="language-ehcache.xm line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="ehcache.xm" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;?xml version=&quot;1.0&quot; encoding=&quot;utf-8&quot;?&gt;</span></span>
<span class="line"><span>&lt;ehcache xmlns:xsi=&quot;http://www.w3.org/2001/XMLSchema-instance&quot;</span></span>
<span class="line"><span>	xsi:noNamespaceSchemaLocation=&quot;../config/ehcache.xsd&quot;&gt;</span></span>
<span class="line"><span>	&lt;!--磁盘保存路径</span></span>
<span class="line"><span>	&lt;diskstore path=&quot;D:\\atguigu\\ehcache&quot;/&gt;</span></span>
<span class="line"><span>	&lt;defaultcache</span></span>
<span class="line"><span>		maxElementsInMemory=&quot;1000&quot;    //内存上最大存储数量</span></span>
<span class="line"><span>		maxElements0nDisk=&quot;10000000&quot;    //磁盘上最大存储数量</span></span>
<span class="line"><span>		eternal=&quot;false&quot;</span></span>
<span class="line"><span>		overflowToDisk=&quot;true&quot;</span></span>
<span class="line"><span>		timeToIdleSeconds=&quot;120&quot;</span></span>
<span class="line"><span>		timeToLiveSeconds=&quot;120&quot;</span></span>
<span class="line"><span>		diskExpiryThreadIntervalseconds=&quot;120&quot;</span></span>
<span class="line"><span>		memoryStoreEvictionPolicy=&quot;LRU&quot;&gt;</span></span>
<span class="line"><span>	&lt;/defaultcache&gt;</span></span>
<span class="line"><span>&lt;/ehcache&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>配置好后需要在映射文件中设置缓存</p><div class="language-mapper.xml line-numbers-mode" data-highlighter="shiki" data-ext="mapper.xml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;cache type=&quot;org.mybatis.caches.ehcache.Ehcachecache&quot;/&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="逆向工程" tabindex="-1"><a class="header-anchor" href="#逆向工程"><span>逆向工程</span></a></h1><p>正向工程：先创建Java实体类，由框架负责根据实体类生成数据库表。Hibernate是支持正向工程的。</p><p>逆向工程：先创建数据库表，由框架负责根据数据库表，反向生成如下资源：</p><ul><li>Java实体类</li><li>Mapper接口</li><li>Mapper映射文件</li></ul><p>逆向工程的配置文件必须是generatorConfig.xml</p><div class="language-generatorconfig.xml line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="generatorconfig.xml" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;</span></span>
<span class="line"><span>&lt;!DocTYPEgeneratorConfiguration</span></span>
<span class="line"><span>	PUBLIC &quot;-//mybatis.org//DTD MyBatis Generator Configuration 1.o//EN&quot;</span></span>
<span class="line"><span>	&quot;http://mybatis.org/dtd/mybatis-generator-config_1_0.dtd&quot;&gt;</span></span>
<span class="line"><span>&lt;generatorConfiguration&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	&lt;!--</span></span>
<span class="line"><span>		targetRuntime：执行生成的逆向工程的版本</span></span>
<span class="line"><span>		MyBatis3Simple：生成基本的CRUD（清新简洁版）只有增删改查五个方法:查询一条数据和查询所有数据以及增删改</span></span>
<span class="line"><span>		MyBatis3：生成带条件的cRUD（奢华尊享版）</span></span>
<span class="line"><span>	--&gt;</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	&lt;context id=&quot;DB2Tables&quot; targetRuntime=&quot;MyBatis3Simple&quot;&gt;</span></span>
<span class="line"><span>		</span></span>
<span class="line"><span>		&lt;!--数据库的连接信息--&gt;</span></span>
<span class="line"><span>		&lt;jdbcConnection driverClass=&quot;com.mysql.jdbc.Driver&quot;</span></span>
<span class="line"><span>			connectionURL=&quot;jdbc:mysql://localhost:3306/mybatis&quot;</span></span>
<span class="line"><span>			userId=&quot;root&quot;</span></span>
<span class="line"><span>			password=&quot;030604&quot;&gt;</span></span>
<span class="line"><span>		&lt;/jdbcConnection&gt;</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>		&lt;!--javaBean的生成策略--&gt;</span></span>
<span class="line"><span>		&lt;javaModelGenerator targetPackage=&quot;com.atguigu.mybatis.pojo&quot; targetProject=&quot;.\\src\\main\\java&quot;&gt;</span></span>
<span class="line"><span>			&lt;property name=&quot;enableSubpackages&quot; value=&quot;true&quot; /&gt;    </span></span>
<span class="line"><span>			&lt;property name=&quot;trimStrings&quot;value=&quot;true&quot;/&gt;</span></span>
<span class="line"><span>		&lt;/javaModelGenerator&gt;</span></span>
<span class="line"><span>		</span></span>
<span class="line"><span>		&lt;!--SQL映射文件的生成策略--&gt;</span></span>
<span class="line"><span>		&lt;SqlMapGenerator targetPackage=&quot;com.atguigu.mybatis.mapper&quot;</span></span>
<span class="line"><span>		targetProject=&quot;.\\src\\main\\resources&quot;&gt;</span></span>
<span class="line"><span>			&lt;property name=&quot;enableSubPackages&quot; value=&quot;true&quot;/&gt;</span></span>
<span class="line"><span>		&lt;/sqlMapGenerator&gt;</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>		&lt;!--Mapper接口的生成策略--&gt;</span></span>
<span class="line"><span>		&lt;javaClientGenerator type=&quot;XMLMAPPER&quot; targetPackage=&quot;com.atguigu.mybatis.mapper&quot;</span></span>
<span class="line"><span>		targetProject=&quot;.\\src\\main\\java&quot;&gt;</span></span>
<span class="line"><span>			&lt;property name=&quot;enableSubPackages&quot; value=&quot;true&quot; /&gt;</span></span>
<span class="line"><span>		&lt;/javaclientGenerator&gt;</span></span>
<span class="line"><span>		</span></span>
<span class="line"><span>		&lt;!--逆向分析的表--&gt;</span></span>
<span class="line"><span>		&lt;!--tableName设置为*号，可以对应所有表，此时不写domainobjectName</span></span>
<span class="line"><span>		&lt;!--domainobjectName属性指定生成出来的实体类的类名--&gt;</span></span>
<span class="line"><span>		&lt;table tableName=&quot;t_emp&quot; domainobjectName=&quot;Emp&quot;/&gt;</span></span>
<span class="line"><span>		&lt;table tableName=&quot;t_dept&quot; domainobjectName=&quot;Dept&quot;/&gt;</span></span>
<span class="line"><span>	&lt;/context&gt;</span></span>
<span class="line"><span>&lt;/generatorConfiguration&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>targetPackage根据哪个包生成 targetProject生成在哪个文件夹 enableSubpackages是否使用子包,如果是true那么targetPackage和targetProject中的点都代表的是一层目录,如果是false那么点只是文件名 trimStrings去掉字符串前面的空格</p>`,26))])}const m=i(c,[["render",u]]),h=JSON.parse('{"path":"/back/mybatis/1/","title":"介绍","lang":"zh-CN","frontmatter":{"title":"介绍","createTime":"2025/04/05 12:12:26","permalink":"/back/mybatis/1/"},"readingTime":{"minutes":17.96,"words":5389},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/MyBatis/介绍.md","headers":[]}');export{m as comp,h as data};
